vector<int> diffWaysToCompute(string expression) {
    unordered_map<string, vector<int>> memo;
    function<vector<int>(string)> dfs = [&](string s) {
        if (memo.find(s) != memo.end()) return memo[s];
        vector<int> res;
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '+' || s[i] == '-' || s[i] == '*') {
                vector<int> left = dfs(s.substr(0, i));
                vector<int> right = dfs(s.substr(i + 1));
                for (int l : left) {
                    for (int r : right) {
                        if (s[i] == '+') res.push_back(l + r);
                        else if (s[i] == '-') res.push_back(l - r);
                        else res.push_back(l * r);
                    }
                }
            }
        }
        if (res.empty()) res.push_back(stoi(s));
        memo[s] = res;
        return res;
    };
    return dfs(expression);
}
